import requests
from requests.auth import HTTPBasicAuth

def get_jira_data(endpoint, auth):
    response = requests.get(
        f"{JIRA_URL}/rest/api/3/{endpoint}",
        auth=HTTPBasicAuth(auth['username'], auth['token'])
    )
    return response.json()


import com.atlassian.jira.component.ComponentAccessor

def workflowManager = ComponentAccessor.getWorkflowManager()
def customFieldManager = ComponentAccessor.getCustomFieldManager()

// Get all workflows
def workflows = workflowManager.getWorkflows()
workflows.each { workflow ->
    println "Analyzing workflow: ${workflow.name}"
    // Analyze steps and transitions
    workflow.steps.each { step ->
        println "  Step: ${step.name}"
        step.actions.each { action ->
            println "    Action: ${action.name}"
            // Analyze post functions
            action.postFunctions.each { postFn ->
                println "      Post-function: ${postFn.class.name}"
            }
        }
    }
}


import com.onresolve.scriptrunner.runner.rest.common.CustomEndpointDelegate
import groovy.transform.BaseScript

@BaseScript CustomEndpointDelegate delegate

workflowAnalysis(httpMethod: "GET", groups: ["jira-administrators"]) { params ->
    // Extract and return workflow data
    def workflows = analyzeWorkflows()
    return workflows
}

