class JiraDocumentationGenerator:
    def __init__(self, jira_client):
        self.client = jira_client
        self.templates = self.load_templates()

    def generate_workflow_doc(self, workflow_data):
        """Genera documentación de workflow en Markdown"""
        template = self.templates['workflow']
        return template.format(
            workflow_name=workflow_data['name'],
            workflow_description=workflow_data['description'],
            status_list=self.format_statuses(workflow_data['statuses']),
            transition_table=self.format_transitions(workflow_data['transitions'])
        )

    def convert_to_confluence(self, markdown_doc):
        """Convierte documentación de Markdown a Confluence"""
        # Implementar conversión específica
